func (s *Server) DownloadFileHandler(c *gin.Context) {
	path := c.Param("path")
	path = strings.TrimPrefix(path, "/")

	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  http.StatusBadRequest,
		})
		return
	}

	safePath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	file, err := os.Open(safePath)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": fmt.Sprintf("file not found: %v", err),
			"code":  http.StatusNotFound,
		})
		return
	}
	defer file.Close()

	info, err := file.Stat()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("failed to get file info: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "cannot download a directory",
			"code":  http.StatusBadRequest,
		})
		return
	}

	contentType := mime.TypeByExtension(filepath.Ext(safePath))
	if contentType == "" {
		contentType = "application/octet-stream"
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(safePath)))
	c.Header("Content-Type", contentType)
	c.Header("Content-Length", fmt.Sprintf("%d", info.Size()))

	http.ServeContent(c.Writer, c.Request, filepath.Base(safePath), info.ModTime(), file)
}

func parseFileMode(modeStr string) os.FileMode {
	if modeStr == "" {
		return 0644
	}

	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil {
		return 0644
	}

	if mode > maxFileMode {
		return 0644
	}

	return os.FileMode(mode)
}

